import{_ as s,o as i,c as a,ao as e}from"./chunks/framework.B9--V88m.js";const g=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/installation.md","filePath":"guide/installation.md","lastUpdated":1781596949000}'),l={name:"guide/installation.md"};function n(h,t,d,o,p,r){return i(),a("div",null,[...t[0]||(t[0]=[e(`<h1 id="Installation" tabindex="-1">Installation <a class="header-anchor" href="#Installation" aria-label="Permalink to &quot;Installation {#Installation}&quot;">​</a></h1><p>This page gets your machine ready to <strong>build</strong> MEX files. Your MATLAB users need none of this — they only need MATLAB.</p><h2 id="What-you-need" tabindex="-1">What you need <a class="header-anchor" href="#What-you-need" aria-label="Permalink to &quot;What you need {#What-you-need}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">Why</th><th style="text-align:right;">How to check</th></tr></thead><tbody><tr><td style="text-align:right;"><strong>Julia 1.12+</strong></td><td style="text-align:right;">Mexicah and <code>juliac</code> require it</td><td style="text-align:right;"><code>julia --version</code></td></tr><tr><td style="text-align:right;"><strong><code>juliac</code></strong></td><td style="text-align:right;">the Julia → binary compiler</td><td style="text-align:right;"><code>juliac --version</code></td></tr><tr><td style="text-align:right;"><strong>A C compiler</strong></td><td style="text-align:right;">builds the tiny MEX loader (<code>gcc</code>/<code>clang</code>)</td><td style="text-align:right;"><code>cc --version</code></td></tr><tr><td style="text-align:right;">MATLAB</td><td style="text-align:right;"><strong>not needed to build</strong> — only to run</td><td style="text-align:right;">—</td></tr></tbody></table><blockquote><p>🐧 <strong>Linux is the supported platform today.</strong> Windows and macOS builds are in progress.</p></blockquote><h2 id="1.-Install-Julia" tabindex="-1">1. Install Julia <a class="header-anchor" href="#1.-Install-Julia" aria-label="Permalink to &quot;1. Install Julia {#1.-Install-Julia}&quot;">​</a></h2><p>If you don&#39;t have Julia, the easiest way is <a href="https://github.com/JuliaLang/juliaup" target="_blank" rel="noreferrer">juliaup</a>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://install.julialang.org</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sh</span></span></code></pre></div><p>Then make sure you&#39;re on 1.12 or newer:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">juliaup</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1.12</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # should print 1.12.x or later</span></span></code></pre></div><h2 id="2.-Install-juliac" tabindex="-1">2. Install <code>juliac</code> <a class="header-anchor" href="#2.-Install-juliac" aria-label="Permalink to &quot;2. Install \`juliac\` {#2.-Install-juliac}&quot;">​</a></h2><p><code>juliac</code> is distributed as a Julia &quot;app&quot;. Install it once:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.Apps.add(&quot;JuliaC&quot;)&#39;</span></span></code></pre></div><p>This drops a <code>juliac</code> launcher in <code>~/.julia/bin</code>. Add that to your <code>PATH</code> (put this in your <code>~/.bashrc</code> / <code>~/.zshrc</code> so it sticks):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.julia/bin:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PATH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>Check it works:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">juliac</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><blockquote><p><strong>If that fails to find <code>JuliaC</code> in the registry</strong> (it can lag on fresh machines), install it straight from source instead:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.Apps.add(url=&quot;https://github.com/JuliaLang/JuliaC.jl.git&quot;)&#39;</span></span></code></pre></div></blockquote><h2 id="3.-Make-sure-a-C-compiler-is-present" tabindex="-1">3. Make sure a C compiler is present <a class="header-anchor" href="#3.-Make-sure-a-C-compiler-is-present" aria-label="Permalink to &quot;3. Make sure a C compiler is present {#3.-Make-sure-a-C-compiler-is-present}&quot;">​</a></h2><p>Mexicah compiles a tiny C gateway loader alongside your MEX. It auto-detects whichever of these is on your <code>PATH</code>:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Platform</th><th style="text-align:right;">Probe order</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;"><strong>Linux / macOS</strong></td><td style="text-align:right;"><code>cc</code> → <code>gcc</code> → <code>clang</code></td><td style="text-align:right;"><code>cc</code> is almost always present</td></tr><tr><td style="text-align:right;"><strong>Windows</strong></td><td style="text-align:right;"><code>gcc</code> → <code>clang</code> → <code>cc</code></td><td style="text-align:right;">install one of the options below</td></tr></tbody></table><p><strong>Linux / macOS</strong> — you almost certainly already have one:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # or: gcc --version / clang --version</span></span></code></pre></div><p>On Ubuntu/Debian, if it&#39;s missing: <code>sudo apt-get install build-essential</code>.</p><p><strong>Windows</strong> — install either option:</p><ul><li><p><strong>MinGW-w64 / MSYS2</strong> (provides <code>gcc</code>):</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">winget install MSYS2.MSYS2</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># then from the MSYS2 shell:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pacman </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">S mingw</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">w64</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ucrt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">x86_64</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gcc</span></span></code></pre></div><p>Add <code>C:\\msys64\\ucrt64\\bin</code> to your <code>PATH</code>.</p></li><li><p><strong>LLVM/Clang</strong> (provides <code>clang</code>):</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">winget install LLVM.LLVM</span></span></code></pre></div><p>The installer offers to add LLVM to <code>PATH</code>; accept it.</p></li></ul><p>Verify whichever you chose:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gcc </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">version   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># MinGW path</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">clang </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">version </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># LLVM path</span></span></code></pre></div><h2 id="4.-Install-Mexicah.jl" tabindex="-1">4. Install Mexicah.jl <a class="header-anchor" href="#4.-Install-Mexicah.jl" aria-label="Permalink to &quot;4. Install Mexicah.jl {#4.-Install-Mexicah.jl}&quot;">​</a></h2><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Pkg</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Pkg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(url </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://github.com/el-oso/Mexicah.jl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>That&#39;s it — head to the <a href="./quickstart">Quickstart</a>.</p><h2 id="Optional-add-ons" tabindex="-1">Optional add-ons <a class="header-anchor" href="#Optional-add-ons" aria-label="Permalink to &quot;Optional add-ons {#Optional-add-ons}&quot;">​</a></h2><p>Mexicah grows extra build features when you load these packages (each is optional — install only what you use):</p><table tabindex="0"><thead><tr><th style="text-align:right;">Package</th><th style="text-align:right;">Unlocks</th></tr></thead><tbody><tr><td style="text-align:right;"><code>Enzyme</code> / <code>ForwardDiff</code></td><td style="text-align:right;"><code>@mexgradient</code> (compile a gradient)</td></tr><tr><td style="text-align:right;"><code>ModelingToolkit</code></td><td style="text-align:right;">compile an ODE right-hand side / Jacobian</td></tr><tr><td style="text-align:right;"><code>DataFrames</code>, <code>JuMP</code></td><td style="text-align:right;">DataFrame and optimization bridges</td></tr><tr><td style="text-align:right;"><code>CUDA</code> + <code>KernelAbstractions</code></td><td style="text-align:right;">GPU kernels via <code>@mexgpukernel</code></td></tr></tbody></table>`,34)])])}const k=s(l,[["render",n]]);export{g as __pageData,k as default};
